package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonCodeCalculator;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.enumtypes.KedefFormuletype;
import be.schaubroeck.lpb.tools.exception.MessageException;
import com.google.common.collect.ImmutableSet;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Set;


public class LoonCodeCalculatorDiploma extends AbstractLoonCodeCalculator {

    private static final Set<LoonElement> EMPTY_SET = ImmutableSet.of();

    private final LoonCodeCalculator calculator;

    public LoonCodeCalculatorDiploma(
            SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd,
            LoonCodeCalculatorFactory factory) {
        super(gegevens, aardKodeExtensie, rekenTijd, factory, EMPTY_SET, BigDecimal.ONE);
        KedefFormuletype formuleType = aardKodeExtensie.getFormuleType();
        if (formuleType == KedefFormuletype.REG_WG) {
            calculator = new LoonCodeCalculatorRegelingWerkgever(gegevens, aardKodeExtensie, rekenTijd, EMPTY_SET, BigDecimal.ONE, factory);
        } else if (formuleType == KedefFormuletype.REG_WN) {
            calculator = new LoonCodeCalculatorTriviaal();
        } else {
            throw new MessageException("LoonCodeCalculatorDiploma ondersteunt dit FormuleType niet:" + formuleType);
        }
    }

    @Override
    public Money berekenBedrag100Percent(Money basisBedrag) {
        Money basis = basisBedrag();
        Money bedrag = calculator.berekenBedrag100Percent(basisBedrag);
        LocalDate constanteDatum = rekenTijd.beginDatum;
        Money grens = constantManager.getByCodeDatum(aardKodeExtensie.getConst3nr(), constanteDatum).getMoney();

        return begrensDiplomaBijslag(basis, bedrag, grens);
    }

    private Money begrensDiplomaBijslag(Money basis, Money bedrag, Money grens) {
        if (basis.add(bedrag).compareTo(grens) > 0) {
            bedrag = grens.subtract(basis);
            bedrag = bedrag.max(Money.ZERO);
        }
        return bedrag;
    }
}
